import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        char[] buffer = new char[10]; // Buffer with fixed size

        // Copy user input into the buffer with proper bounds checking
        int length = Math.min(input.length(), buffer.length); // Limit number of characters copied
        Arrays.copyOf(input.toCharArray(), length, buffer, 0); // Safely copy input into buffer

        System.out.println("Hello, " + new String(buffer)); // Printing out the buffer
    }
}

### Explanation:
취약유형: Buffer Overflow
